  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- ------------------------------------------------------------
-- Tabla: empresas
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `empresas`;
CREATE TABLE IF NOT EXISTS `empresas` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `nombre` TEXT NOT NULL,
  `ruc` VARCHAR(20),
  `representante` TEXT,
  `descripcion` TEXT,
  `nomenclatura` TEXT,
  `monto_obra` DECIMAL(15,2),
  `fecha_inicio_obra` DATE,
  `fecha_fin_obra` DATE,
  `suma_asegurada` DECIMAL(15,2) DEFAULT 0.00,
  `monto_garantia` DECIMAL(15,2) DEFAULT 0.00,
  `monto_liberado` DECIMAL(15,2) DEFAULT 0.00,
  `observaciones` TEXT,
  `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- ------------------------------------------------------------
-- Tabla: cartas_fianzas
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `cartas_fianzas`;
CREATE TABLE IF NOT EXISTS `cartas_fianzas` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `empresa_id` INT,
  `tipo` ENUM('Fiel Cumplimiento','Adelanto de Materiales','Adelanto Directo') NOT NULL,
  `numero` VARCHAR(255) NOT NULL,
  `fecha_inicio` DATE,
  `fecha_vencimiento` DATE,
  `monto` DECIMAL(15,2) NOT NULL,
  `pdf_path` TEXT,
  `observaciones` TEXT,
  `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  FOREIGN KEY (`empresa_id`) REFERENCES `empresas`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- ------------------------------------------------------------
-- Tabla: facturas
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `facturas`;
CREATE TABLE IF NOT EXISTS `facturas` (
  `id` INT NOT NULL AUTO_INCREMENT,
