  `numero` VARCHAR(255) NOT NULL,
  `monto` DECIMAL(15,2) NOT NULL,
  `tipo_fianza_relacionada` ENUM('Fiel Cumplimiento','Adelanto de Materiales','Adelanto Directo'),
